import { useEffect, useState } from "react";
import PageHeader from "../components/PageHeader";
import { createAppointment, getAppointments } from "../services/api";

const nearbyHospitals = [
  { name: "City Care Hospital", address: "12 Wellness Avenue", distance: "2.3 km" },
  { name: "Green Valley Medical Center", address: "88 River Road", distance: "4.1 km" },
  { name: "Sunrise Multispeciality", address: "7 Central Plaza", distance: "5.8 km" },
];

export default function UserAppointmentsPage() {
  const [items, setItems] = useState([]);
  const [form, setForm] = useState({ hospital_name: "", hospital_address: "", appointment_date: "", appointment_time: "", notes: "" });

  const load = async () => setItems(await getAppointments());
  useEffect(() => { load(); }, []);

  const handleSubmit = async (event) => {
    event.preventDefault();
    await createAppointment(form);
    setForm({ hospital_name: "", hospital_address: "", appointment_date: "", appointment_time: "", notes: "" });
    load();
  };

  return (
    <>
      <PageHeader title="Appointment Scheduling" description="A separate booking workspace for requesting, reviewing, and planning appointments." />
      <div className="panel">
        <h3 className="section-title">Nearby Hospitals</h3>
        <div className="shortcut-grid">
          {nearbyHospitals.map((hospital) => (
            <button
              type="button"
              className="shortcut-card shortcut-button"
              key={hospital.name}
              onClick={() => setForm({ ...form, hospital_name: hospital.name, hospital_address: hospital.address })}
            >
              <strong>{hospital.name}</strong>
              <span>{hospital.address}</span>
              <span>{hospital.distance}</span>
            </button>
          ))}
        </div>
      </div>
      <div className="split-layout">
        <div className="panel">
          <form onSubmit={handleSubmit}>
            <div className="form-grid">
              <div className="field"><label>Hospital</label><input value={form.hospital_name} onChange={(e) => setForm({ ...form, hospital_name: e.target.value })} /></div>
              <div className="field"><label>Address</label><input value={form.hospital_address} onChange={(e) => setForm({ ...form, hospital_address: e.target.value })} /></div>
              <div className="field"><label>Date</label><input type="date" value={form.appointment_date} onChange={(e) => setForm({ ...form, appointment_date: e.target.value })} /></div>
              <div className="field"><label>Time</label><input type="time" value={form.appointment_time} onChange={(e) => setForm({ ...form, appointment_time: e.target.value })} /></div>
            </div>
            <div className="field"><label>Notes</label><textarea value={form.notes} onChange={(e) => setForm({ ...form, notes: e.target.value })} /></div>
            <button className="btn btn-primary" type="submit">Request Appointment</button>
          </form>
        </div>
        <div className="panel">
          <h3 className="section-title">Appointment Requests</h3>
          <div className="summary-list">
            {items.map((item) => <div className="summary-item" key={item.id}><strong>{item.hospital_name}</strong><div>{item.appointment_date} at {item.appointment_time}</div><span className="pill">{item.status}</span></div>)}
          </div>
        </div>
      </div>
    </>
  );
}
